            <AddProjectField
              id="add-project-directory-display"
              label="Directory"
            >
              <input
                {...directoryPickerInputAttributes}
                ref={directoryInputRef}
                id="add-project-directory"
                type="file"
                name="directory"
                tabIndex={-1}
                aria-hidden="true"
                hidden
                multiple
